// ============================================================
// NODE: Check for Empty Results
// If no prospects need processing, stop the workflow early
// to avoid unnecessary API calls.
// ============================================================

const items = $input.all();

if (!items || items.length === 0 || !items[0].json.id) {
  // No prospects to process — stop workflow
  return [];
}

return items;

// ============================================================
// NODE: Build Spacebot Prompt
// Constructs the message payload for Agent 05 (Creative Ideas)
// based on the prospect's score and enrichment data.
// ============================================================

const p = $input.item.json;

// Determine format based on score
// golden → Format A (3 full bullet ideas)
// strong → Format A (test — can switch to B)
// must_have → Format B (one-liner)
const score = p.score || 'must_have';
let format = 'B'; // default: one-liner for volume
if (score === 'golden' || score === 'strong') {
  format = 'A'; // full 3 bullets for high-value
}

// Determine market
const country = (p.country || '').toUpperCase();
const market = (country === 'UK' || country === 'GB' || country === 'UNITED KINGDOM') ? 'UK' : 'US';

// Build the prompt
const message = [
  `Company: ${p.company_name}`,
  `Description: ${p.company_description || 'No description available'}`,
  `Industry: ${p.industry || 'Unknown'}`,
  `Employee Count: ${p.employee_count || 'Unknown'}`,
  `Market: ${market}`,
  `Format: ${format}`,
  `Business Type: ${p.business_type || 'B2B'}`,
  p.total_funding ? `Funding: ${p.funding_stage || ''} — ${p.total_funding}` : '',
  p.contact_title ? `Contact Role: ${p.contact_title}` : ''
].filter(Boolean).join('\n');

return {
  json: {
    prospect_id: p.id,
    prospect: p,
    spacebot_payload: {
      message: message
    },
    format: format,
    market: market
  }
};

// ============================================================
// NODE: Parse Spacebot Response
// Extracts structured creative ideas from Agent 05's response.
// Handles both Format A (3 bullets) and Format B (one-liner).
// ============================================================

const input = $input.item.json;
const response = input; // The HTTP response
const prospect = $('Build Spacebot Prompt').item.json;
const format = prospect.format;

// Extract the agent's text response
// Adjust these field paths based on your Spacebot API response structure
const agentText = response.message || response.response || response.content || response.text || '';

let creativeIdeas = {};

if (!agentText) {
  // Agent returned empty — flag for retry
  creativeIdeas = {
    status: 'failed',
    error: 'Empty response from Agent 05',
    raw_response: JSON.stringify(response).substring(0, 500)
  };
} else if (format === 'A') {
  // Format A: Extract 3 bullet ideas
  // Try to parse numbered ideas (1. xxx  2. xxx  3. xxx)
  const lines = agentText.split('\n').filter(l => l.trim());
  const ideas = [];

  for (const line of lines) {
    const match = line.match(/^\d+[\.\)]\s*(.+)/);
    if (match) {
      ideas.push(match[1].trim());
    }
  }

  // Fallback: if no numbered format found, split by sentences
  if (ideas.length < 3) {
    const sentences = agentText.split(/[.!?]+/).filter(s => s.trim().length > 20);
    while (ideas.length < 3 && sentences.length > 0) {
      ideas.push(sentences.shift().trim());
    }
  }

  creativeIdeas = {
    status: 'complete',
    format: 'A',
    idea_1: ideas[0] || '',
    idea_2: ideas[1] || '',
    idea_3: ideas[2] || '',
    one_liner: ideas[0] || '', // Use first idea as one-liner fallback
    raw_response: agentText
  };
} else {
  // Format B: Extract one-liner
  const oneLiner = agentText.split('\n').filter(l => l.trim())[0] || agentText.substring(0, 200);

  creativeIdeas = {
    status: 'complete',
    format: 'B',
    idea_1: '',
    idea_2: '',
    idea_3: '',
    one_liner: oneLiner.trim(),
    raw_response: agentText
  };
}

return {
  json: {
    prospect_id: prospect.prospect_id,
    creative_ideas: creativeIdeas
  }
};

// ============================================================
// NODE: Summary Stats
// Logs processing results for monitoring.
// ============================================================

const items = $('Supabase: Update Ideas').all();
const total = items.length;
const successful = items.filter(i => i.json.creative_ideas?.status === 'complete').length;
const failed = total - successful;

return {
  json: {
    summary: {
      total_processed: total,
      successful: successful,
      failed: failed,
      timestamp: new Date().toISOString()
    }
  }
};
